What does this program print?

```cpp
#include <iostream>
#include <vector>

int main()
{
    std::vector<int> v { 1, 2, 3 };
    for (int x : v)
        x *= 10;
    for (int x : v)
        std::cout << x << ' ';
    std::cout << '\n';
}
```

